  1	import { isAbsolute, relative, resolve } from "node:path";
  2	
  3	import { loadRunConfig } from "./config-schema";
  4	import { resolveGitRepoRoot } from "./git-repo";
  5	import { createProviderAdapter, type ProviderName } from "./provider-adapters";
  6	import type { CliError } from "./result-contracts";
  7	
  8	interface QuickFixResultPayload {
  9	  provider: ProviderName;
 10	  model: string;
 11	  rawProviderOutput: string;
 12	}
 13	
 14	export interface QuickFixWorkflowResult {
 15	  outcome: "ready-for-verification" | "needs-more-routing" | "blocked";
 16	  result?: QuickFixResultPayload;
 17	  errors: CliError[];
 18	  warnings: string[];
 19	}
 20	
 21	function blockedError(code: string, message: string, detail?: string): CliError {
 22	  return {
 23	    code,
 24	    message,
 25	    ...(detail ? { detail } : {}),
 26	  };
 27	}
 28	
 29	function providerForHarness(harness: "codex" | "copilot" | "none"): ProviderName {
 30	  if (harness === "none") {
 31	    return "claude-code";
 32	  }
 33	
 34	  return harness;
 35	}
 36	
 37	function executionFailureError(input: {
 38	  provider: ProviderName;
 39	  stderr: string;
 40	  errorCode?: string;
 41	}): CliError {
 42	  if (input.errorCode === "ENOENT") {
 43	    return blockedError(
 44	      "PROVIDER_UNAVAILABLE",
 45	      `Provider executable is unavailable for ${input.provider}.`,
 46	      input.stderr
 47	    );
 48	  }
 49	
 50	  return blockedError(
 51	    "PROVIDER_UNAVAILABLE",
 52	    `Provider execution failed for ${input.provider}.`,
 53	    input.stderr
 54	  );
 55	}
 56	
 57	function isWithinRoot(root: string, target: string): boolean {
 58	  const relativePath = relative(root, target);
 59	  return (
 60	    relativePath.length === 0 ||
 61	    (!relativePath.startsWith("..") && !isAbsolute(relativePath))
 62	  );
 63	}
 64	
 65	async function resolveWorkingDirectory(input: {
 66	  specPackRoot: string;
 67	  workingDirectory?: string;
 68	}): Promise<{ workingDirectory?: string; errors?: CliError[] }> {
 69	  const repoRoot = await resolveGitRepoRoot(input.specPackRoot);
 70	  if (!repoRoot) {
 71	    return {
 72	      errors: [
 73	        blockedError(
 74	          "INVALID_SPEC_PACK",
 75	          `Spec-pack root is not inside a git repo: ${resolve(input.specPackRoot)}`
 76	        ),
 77	      ],
 78	    };
 79	  }
 80	
 81	  if (input.workingDirectory) {
 82	    const workingDirectory = resolve(input.workingDirectory);
 83	    if (!isWithinRoot(repoRoot, workingDirectory)) {
 84	      return {
 85	        errors: [
 86	          blockedError(
 87	            "INVALID_WORKING_DIRECTORY",
 88	            "Quick-fix working directory must stay inside the resolved repo root.",
 89	            `repoRoot=${repoRoot}; workingDirectory=${workingDirectory}`
 90	          ),
 91	        ],
 92	      };
 93	    }
 94	
 95	    return {
 96	      workingDirectory,
 97	    };
 98	  }
 99	
100	  return {
101	    workingDirectory: repoRoot,
102	  };
103	}
104	
105	export async function runQuickFix(input: {
106	  specPackRoot: string;
107	  request: string;
108	  workingDirectory?: string;
109	  configPath?: string;
110	  env?: Record<string, string | undefined>;
111	}): Promise<QuickFixWorkflowResult> {
112	  const config = await loadRunConfig({
113	    specPackRoot: input.specPackRoot,
114	    configPath: input.configPath,
115	  });
116	  const provider = providerForHarness(config.quick_fixer.secondary_harness);
117	  const workingDirectoryResolution = await resolveWorkingDirectory({
118	    specPackRoot: input.specPackRoot,
119	    workingDirectory: input.workingDirectory,
120	  });
121	  if (workingDirectoryResolution.errors) {
122	    return {
123	      outcome: "blocked",
124	      errors: workingDirectoryResolution.errors,
125	      warnings: [],
126	    };
127	  }
128	  const workingDirectory = workingDirectoryResolution.workingDirectory;
129	  if (!workingDirectory) {
130	    return {
131	      outcome: "blocked",
132	      errors: [
133	        blockedError(
134	          "INVALID_WORKING_DIRECTORY",
135	          "Quick-fix working directory could not be resolved."
136	        ),
137	      ],
138	      warnings: [],
139	    };
140	  }
141	  const adapter = createProviderAdapter(provider, {
142	    env: input.env,
143	  });
144	  const execution = await adapter.execute({
145	    prompt: input.request,
146	    cwd: workingDirectory,
147	    model: config.quick_fixer.model,
148	    reasoningEffort: config.quick_fixer.reasoning_effort,
149	    timeoutMs: 30_000,
150	  });
151	
152	  if (execution.exitCode !== 0) {
153	    return {
154	      outcome: "blocked",
155	      errors: [
156	        executionFailureError({
157	          provider,
158	          stderr: execution.stderr,
159	          errorCode: execution.errorCode,
160	        }),
161	      ],
162	      warnings: [],
163	    };
164	  }
165	
166	  const rawProviderOutput = execution.stdout;
167	  if (rawProviderOutput.trim().length === 0) {
168	    return {
169	      outcome: "needs-more-routing",
170	      result: {
171	        provider,
172	        model: config.quick_fixer.model,
173	        rawProviderOutput,
174	      },
175	      errors: [],
176	      warnings: [
177	        "Quick-fix provider returned no stdout; inspect the run and choose the next routing step explicitly.",
178	      ],
179	    };
180	  }
181	
182	  return {
183	    outcome: "ready-for-verification",
184	    result: {
185	      provider,
186	      model: config.quick_fixer.model,
187	      rawProviderOutput,
188	    },
189	    errors: [],
190	    warnings: [],
191	  };
192	}

