 18	interface OutputEnvelope {
 19	  command: string;
 20	  version: 1;
 21	  status: CliStatus;
 22	  outcome: string;
 23	  result?: unknown;
 24	  errors: CliError[];
 25	  warnings: string[];
 26	  artifacts: CliArtifactRef[];
 27	  startedAt: string;
 28	  finishedAt: string;
 29	}
