 31	function renderHumanSummary(envelope: OutputEnvelope) {
 32	  if (
 33	    typeof envelope.result !== "object" ||
 34	    envelope.result === null ||
 35	    !("provider" in envelope.result)
 36	  ) {
 37	    return `quick-fix: ${envelope.outcome}`;
 38	  }
 39	
 40	  const result = envelope.result as {
 41	    provider: string;
 42	  };
 43	  return [
 44	    `quick-fix: ${envelope.outcome}`,
 45	    `provider: ${result.provider}`,
 46	  ].join("\n");
 47	}
 48	
 49	function emitOutput(params: {
 50	  envelope: OutputEnvelope;
 51	  json: boolean;
 52	}) {
 53	  if (params.json) {
 54	    console.log(JSON.stringify(params.envelope));
 55	    return;
 56	  }
 57	
 58	  console.log(renderHumanSummary(params.envelope));
 59	}
