 61	async function resolveRequest(args: {
 62	  "request-file"?: string;
 63	  "request-text"?: string;
 64	}): Promise<string> {
 65	  const requestSources = [
 66	    typeof args["request-file"] === "string" ? "file" : null,
 67	    typeof args["request-text"] === "string" ? "text" : null,
 68	  ].filter(Boolean);
 69	
 70	  if (requestSources.length !== 1) {
 71	    throw new Error("Provide exactly one of --request-file or --request-text.");
 72	  }
 73	
 74	  if (args["request-text"]) {
 75	    const request = args["request-text"].trim();
 76	    if (request.length === 0) {
 77	      throw new Error("--request-text cannot be empty.");
 78	    }
 79	    return request;
 80	  }
 81	
 82	  const request = (await readTextFile(resolve(args["request-file"]!))).trim();
 83	  if (request.length === 0) {
 84	    throw new Error("--request-file cannot point to an empty task description.");
 85	  }
 86	
 87	  return request;
 88	}
 89	
 90	function hasFlag(rawArgs: string[], flag: string): boolean {
 91	  return rawArgs.some((arg) => arg === flag || arg.startsWith(`${flag}=`));
 92	}
 93	
 94	function assertNoLegacyStoryAwareFlags(rawArgs: string[]) {
 95	  if (
 96	    hasFlag(rawArgs, "--story-id") ||
 97	    hasFlag(rawArgs, "--story-title") ||
 98	    hasFlag(rawArgs, "--story-path") ||
 99	    hasFlag(rawArgs, "--scope-file")
100	  ) {
101	    throw new Error(
102	      "quick-fix does not accept story-aware flags such as --story-id, --story-title, --story-path, or --scope-file."
103	    );
104	  }
105	}
106	
107	export default defineCommand({
108	  meta: {
109	    name: "quick-fix",
110	    description: "Run a bounded quick-fix with a free-form task description.",
111	  },
112	  args: {
113	    "spec-pack-root": {
114	      type: "string",
115	      description: "Absolute or relative path to the spec-pack root",
116	      required: true,
117	    },
118	    "request-file": {
119	      type: "string",
120	      description: "Path to a file containing the free-form quick-fix task",
121	    },
122	    "request-text": {
123	      type: "string",
124	      description: "Inline free-form quick-fix task description",
125	    },
126	    "working-directory": {
127	      type: "string",
128	      description: "Working directory for the quick-fix provider invocation",
129	    },
130	    config: {
131	      type: "string",
132	      description: "Explicit run-config file relative to the spec-pack root",
133	    },
134	    json: {
135	      type: "boolean",
136	      description: "Emit the structured JSON envelope on stdout",
137	    },
138	  },
139	  async run({ args, rawArgs }) {
140	    const startedAt = new Date().toISOString();
141	    const artifactPath = await nextArtifactPath(args["spec-pack-root"], "quick-fix");
142	
143	    try {
144	      assertNoLegacyStoryAwareFlags(rawArgs);
145	      const request = await resolveRequest(args);
146	      const outcome = await runQuickFix({
147	        specPackRoot: args["spec-pack-root"],
148	        request,
149	        workingDirectory: args["working-directory"],
150	        configPath: args.config,
151	        env: process.env,
152	      });
153	      const envelope = cliResultEnvelopeSchema(z.unknown()).parse(
154	        createResultEnvelope({
155	          command: "quick-fix",
156	          outcome: outcome.outcome,
157	          result: outcome.result,
158	          errors: outcome.errors,
159	          warnings: outcome.warnings,
160	          artifacts: [
161	            {
162	              kind: "result-envelope",
163	              path: artifactPath,
164	            },
165	          ],
166	          startedAt,
167	          finishedAt: new Date().toISOString(),
168	        })
169	      );
170	
171	      await writeJsonArtifact(artifactPath, envelope);
172	      emitOutput({
173	        envelope,
174	        json: Boolean(args.json),
175	      });
176	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
177	    } catch (error) {
178	      const message = error instanceof Error ? error.message : String(error);
179	      const code =
180	        message.includes("--request-") ||
181	        message.includes("Provide exactly one") ||
182	        message.includes("does not accept story-aware flags")
183	          ? "INVALID_INVOCATION"
184	          : message.toLowerCase().includes("config")
185	            ? "INVALID_RUN_CONFIG"
186	            : "UNEXPECTED_ERROR";
187	      const outcome = code === "INVALID_RUN_CONFIG" ? "blocked" : "error";
188	      const envelope: OutputEnvelope = createResultEnvelope({
189	        command: "quick-fix",
190	        outcome,
191	        errors: [
192	          {
193	            code,
194	            message,
195	          },
196	        ],
197	        artifacts: [
198	          {
199	            kind: "result-envelope",
200	            path: artifactPath,
201	          },
202	        ],
203	        startedAt,
204	        finishedAt: new Date().toISOString(),
205	      });
206	
207	      await writeJsonArtifact(artifactPath, envelope);
208	      emitOutput({
209	        envelope,
210	        json: Boolean(args.json),
211	      });
212	      process.exitCode = exitCodeForStatus(envelope.status, envelope.outcome);
213	    }
214	  },
215	});

