339	export function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {
340	  return z
341	    .object({
342	      command: z.string().min(1),
343	      version: z.literal(1),
344	      status: cliStatusSchema,
345	      outcome: z.string().min(1),
346	      result: resultSchema.optional(),
347	      errors: z.array(cliErrorSchema),
348	      warnings: z.array(z.string()),
349	      artifacts: z.array(cliArtifactRefSchema),
350	      startedAt: z.string().min(1),
351	      finishedAt: z.string().min(1),
352	    })
353	    .superRefine((value, ctx) => {
354	      const expectedStatus = statusForOutcome(value.outcome);
355	      if (expectedStatus !== value.status) {
356	        ctx.addIssue({
357	          code: z.ZodIssueCode.custom,
358	          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,
359	          path: ["status"],
360	        });
361	      }
362	
363	      if (
364	        value.result &&
365	        typeof value.result === "object" &&
366	        "outcome" in value.result &&
367	        typeof value.result.outcome === "string" &&
368	        value.result.outcome !== value.outcome
369	      ) {
370	        ctx.addIssue({
371	          code: z.ZodIssueCode.custom,
372	          message: `Envelope outcome '${value.outcome}' does not match result outcome '${value.result.outcome}'`,
373	          path: ["outcome"],
374	        });
375	      }
376	    });
377	}
