 8	interface CodexAdapterOptions {
 9	  env?: Record<string, string | undefined>;
10	}
11	
12	export function createCodexAdapter(
13	  options: CodexAdapterOptions = {}
14	): ProviderAdapter {
15	  return {
16	    provider: "codex",
17	    async execute<TResult>(
18	      request: ProviderExecutionRequest<TResult>
19	    ) {
20	      const args = request.resumeSessionId
21	        ? [
22	            "exec",
23	            "resume",
24	            "--json",
25	            request.resumeSessionId,
26	            request.prompt,
27	          ]
28	        : [
29	            "exec",
30	            "--json",
31	            "-m",
32	            request.model,
33	            "-c",
34	            `model_reasoning_effort=${request.reasoningEffort}`,
35	            request.prompt,
36	          ];
37	      const execution = await runProviderCommand({
38	        provider: "codex",
39	        executable: "codex",
40	        args,
41	        cwd: request.cwd,
42	        env: options.env,
43	        timeoutMs: request.timeoutMs,
44	      });
45	
46	      if (execution.exitCode !== 0) {
47	        return execution;
48	      }
49	
50	      const parsed = parseProviderPayload({
51	        stdout: execution.stdout,
52	        resultSchema: request.resultSchema,
53	      });
54	
55	      return {
56	        ...execution,
57	        sessionId: parsed.sessionId ?? request.resumeSessionId,
58	        parsedResult: parsed.parsedResult,
59	        parseError: parsed.parseError,
60	      };
61	    },
62	  };
63	}

