 38	function redactSensitiveText(text: string): string {
 39	  return text
 40	    .replace(/\bBearer\s+[A-Za-z0-9._-]+\b/gi, "Bearer [REDACTED]")
 41	    .replace(/\b(token|auth|authorization|api[_-]?key)\s*[:=]\s*\S+/gi, "$1=[REDACTED]");
 42	}
 43	
 44	function extractSessionId(value: Record<string, unknown>): string | undefined {
 45	  for (const key of ["sessionId", "session_id"]) {
 46	    const candidate = value[key];
 47	    if (typeof candidate === "string" && candidate.trim().length > 0) {
 48	      return candidate.trim();
 49	    }
 50	  }
 51	
 52	  return undefined;
 53	}
 54	
 55	function parseNestedJson(value: unknown): unknown {
 56	  if (typeof value !== "string") {
 57	    return value;
 58	  }
 59	
 60	  try {
 61	    return JSON.parse(value);
 62	  } catch {
 63	    return undefined;
 64	  }
 65	}
 66	
 67	export function parseProviderPayload<TResult>(input: {
 68	  stdout: string;
 69	  resultSchema?: z.ZodType<TResult>;
 70	}): {
 71	  parsedResult?: TResult;
 72	  sessionId?: string;
 73	  parseError?: string;
 74	} {
 75	  const trimmed = input.stdout.trim();
 76	  if (trimmed.length === 0) {
 77	    return {
 78	      parseError: "Provider stdout was empty.",
 79	    };
 80	  }
 81	
 82	  let root: unknown;
 83	  try {
 84	    root = JSON.parse(trimmed);
 85	  } catch {
 86	    return {
 87	      parseError: "Provider stdout was not exact JSON.",
 88	    };
 89	  }
 90	
 91	  if (!root || typeof root !== "object" || Array.isArray(root)) {
 92	    return {
 93	      parseError: "Provider stdout was not a JSON object.",
 94	    };
 95	  }
 96	
 97	  const rootRecord = root as Record<string, unknown>;
 98	  const resultSchema = input.resultSchema ?? z.unknown();
 99	  const direct = resultSchema.safeParse(rootRecord);
100	  if (direct.success) {
101	    return {
102	      parsedResult: direct.data as TResult,
103	      sessionId: extractSessionId(rootRecord),
104	    };
105	  }
106	
107	  for (const field of ["result", "text"]) {
108	    const nested = parseNestedJson(rootRecord[field]);
109	    const parsed = resultSchema.safeParse(nested);
110	    if (parsed.success) {
111	      return {
112	        parsedResult: parsed.data as TResult,
113	        sessionId: extractSessionId(rootRecord),
114	      };
115	    }
116	  }
117	
118	  return {
119	    parseError: "Provider output did not match the expected JSON payload.",
120	  };
121	}
